module pulse_generator (
    input clk,
    input reset,
    output reg pulse
);

    reg [1:0] obf_count;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            obf_count <= 0;
            pulse <= 0;
        end else if (obf_count == 2) begin
            pulse <= 1;
            obf_count <= 0;
        end else begin
            obf_count <= obf_count + 1;
            pulse <= 0;
        end
    end
endmodule
